+import { describe, it, expect } from 'vitest';
+import { formatDuration } from '../formatDuration';
+
+describe('formatDuration', () => {
+  describe('finite-positive durations', () => {
+    it('formats 2 minutes', () => {
+      expect(formatDuration(120_000)).toBe('2m');
+    });
+
+    it('formats 59 minutes (just under 1 hour)', () => {
+      expect(formatDuration(59 * 60_000)).toBe('59m');
+    });
+
+    it('formats whole hours without minute remainder', () => {
+      expect(formatDuration(2 * 3_600_000)).toBe('2h');
+    });
+
+    it('formats hours + minutes when there is a remainder', () => {
+      expect(formatDuration(2 * 3_600_000 + 5 * 60_000)).toBe('2h 5m');
+    });
+
+    it('formats whole days', () => {
+      expect(formatDuration(86_400_000)).toBe('1d');
+    });
+  });
+
+  describe('degenerate durations', () => {
+    it('returns "< 1m" for sub-minute positive durations', () => {
+      expect(formatDuration(45_000)).toBe('< 1m');
+    });
+
+    it('returns "< 1m" for zero', () => {
+      expect(formatDuration(0)).toBe('< 1m');
+    });
+
+    it('returns "< 1m" for negative durations (clock skew)', () => {
+      expect(formatDuration(-1_000)).toBe('< 1m');
+      expect(formatDuration(-3_600_000)).toBe('< 1m');
+    });
+  });
+
+  describe('non-finite inputs', () => {
+    it('returns "—" for NaN', () => {
+      expect(formatDuration(NaN)).toBe('—');
+    });
+
+    it('returns "—" for Infinity', () => {
+      expect(formatDuration(Infinity)).toBe('—');
+      expect(formatDuration(-Infinity)).toBe('—');
+    });
+  });
+});
