+/**
+ * Format a duration in milliseconds as a human-readable short string.
+ *
+ *   formatDuration(45_000)    → "< 1m"
+ *   formatDuration(120_000)   → "2m"
+ *   formatDuration(7_200_000) → "2h"
+ *   formatDuration(7_500_000) → "2h 5m"
+ *   formatDuration(86_400_000) → "1d"
+ *   formatDuration(0)         → "< 1m"
+ *   formatDuration(-1000)     → "< 1m"   (clock skew on cross-system timestamps)
+ *   formatDuration(NaN)       → "—"
+ *
+ * The single `ms < 60_000` guard covers three cases that should not be
+ * rendered as a literal duration:
+ *   (a) sub-minute durations (which would otherwise round to "0m"),
+ *   (b) zero durations,
+ *   (c) negative values from mild cross-system clock skew (e.g. PR
+ *       openedAt vs. first review's startedAt on a different host).
+ *
+ * The `Number.isFinite` guard prevents `NaN` (e.g. from an invalid
+ * timestamp string) from rendering as `"NaNd"` after falling through
+ * every comparison. Falsy values like `null`/`undefined` also fail the
+ * isFinite check and degrade to `'—'`.
+ *
+ * Replaces the per-page copies that had drifted across the codebase.
+ * Other files still maintain their own local copies; migrating them
+ * is tracked as a separate refactor since signatures vary between
+ * call sites.
+ */
+export function formatDuration(ms: number): string {
+  if (!Number.isFinite(ms)) return '—';
+  if (ms < 60_000) return '< 1m';
+  const minutes = Math.floor(ms / 60_000);
+  if (minutes < 60) return `${minutes}m`;
+  const hours = Math.floor(minutes / 60);
+  const remMin = minutes % 60;
+  if (hours < 24) return remMin === 0 ? `${hours}h` : `${hours}h ${remMin}m`;
+  const days = Math.floor(hours / 24);
+  return `${days}d`;
+}
