+/**
+ * Format a number using the user's locale (e.g. `26113` → `"26,113"`).
+ *
+ * Replaces the per-page copies in CodeReviewPullDetailPage and UsageDashboard.
+ */
+export function formatNumber(n: number): string {
+  return n.toLocaleString();
+}
